import{_ as a,C as c,o as t,c as d,an as o,b as n,w as r,a as i,E as l,ao as h}from"./chunks/framework.CTqRDTHW.js";const y=JSON.parse('{"title":"Feature: decouple-service-codenames","description":"","frontmatter":{},"headers":[],"relativePath":"014-decouple-service-codenames/spec.md","filePath":"014-decouple-service-codenames/spec.md","lastUpdated":1772727487000}'),p={name:"014-decouple-service-codenames/spec.md"};function m(u,e,g,v,f,b){const s=c("Mermaid");return t(),d("div",null,[e[1]||(e[1]=o('<h1 id="feature-decouple-service-codenames" tabindex="-1">Feature: decouple-service-codenames <a class="header-anchor" href="#feature-decouple-service-codenames" aria-label="Permalink to &quot;Feature: decouple-service-codenames&quot;">​</a></h1><blockquote><p><strong>Spec</strong>: 014-decouple-service-codenames <strong>Date</strong>: 2026-03-05 <strong>Status</strong>: Draft</p></blockquote><h2 id="target-modules" tabindex="-1">Target Modules <a class="header-anchor" href="#target-modules" aria-label="Permalink to &quot;Target Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Impact</th></tr></thead><tbody><tr><td>Services — reasoner</td><td><code>services/reasoner/</code></td><td>High — Python package rename + NATS subjects + Pulsar topics + DB schema + stale vector-db refs</td></tr><tr><td>Services — cortex</td><td><code>services/cortex/</code></td><td>Medium — Go config hostname defaults</td></tr><tr><td>Services — persistence</td><td><code>services/persistence/</code></td><td>Medium — container rename <code>arc-sql-db</code> → <code>arc-persistence</code></td></tr><tr><td>Services — vector</td><td><code>services/vector/</code></td><td>High — remove dead Qdrant service entirely (replaced by pgvector)</td></tr><tr><td>Services — flags</td><td><code>services/flags/</code></td><td>Low — DATABASE_URL hostname update</td></tr><tr><td>Services — otel</td><td><code>services/otel/</code></td><td>Low — OTEL collector endpoint hostname update</td></tr><tr><td>Services — data.mk</td><td><code>services/data.mk</code></td><td>Low — remove vector-db targets, update sql-db refs</td></tr><tr><td>Contracts</td><td><code>services/reasoner/contracts/asyncapi.yaml</code></td><td>Medium — subject definitions updated</td></tr><tr><td>SDK</td><td><code>sdk/python/</code></td><td>Low — verify no import of <code>sherlock</code> package</td></tr><tr><td>Docs</td><td><code>docs/</code></td><td>Low — verify no hardcoded codenames in code samples</td></tr></tbody></table><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Codenames (Sherlock, Flash, Sonic, Oracle, etc.) are a team fun-factor — they must never be coupled into source code, wire protocols, or config defaults. Currently they leak into four coupling tiers: Python module paths, NATS/Pulsar wire subjects, Postgres schema names, and Go config hostname defaults. This spec defines a clean boundary: codenames stay in <code>service.yaml</code> metadata and CLI display; everywhere else uses the functional service role name.</p><p>This spec also removes the dead Qdrant service (<code>services/vector/</code> — codename Cerebro) which was replaced by pgvector inside the existing Postgres service. The reasoner already uses pgvector exclusively; Qdrant has zero code consumers. Removing it eliminates dead infrastructure and confusion. Simultaneously, the Postgres container is renamed from the artifact name <code>arc-sql-db</code> to the functional name <code>arc-persistence</code> for consistency.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2>',8)),(t(),n(h,null,{default:r(()=>[l(s,{id:"mermaid-150",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22Before%20%E2%80%94%20Coupled%22%0A%20%20%20%20%20%20%20%20A1%5Bfrom%20sherlock.xxx%20import%5D%20--%3E%20A2%5Bsherlock.v1.chat%20NATS%5D%0A%20%20%20%20%20%20%20%20A2%20--%3E%20A3%5Bsherlock.vector_stores%20schema%5D%0A%20%20%20%20%20%20%20%20A3%20--%3E%20A4%5Barc-oracle%20%2F%20arc-flash%20%2F%20arc-sonic%20hosts%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22After%20%E2%80%94%20Decoupled%22%0A%20%20%20%20%20%20%20%20B1%5Bfrom%20reasoner.xxx%20import%5D%20--%3E%20B2%5Breasoner.v1.chat%20NATS%5D%0A%20%20%20%20%20%20%20%20B2%20--%3E%20B3%5Breasoner.vector_stores%20schema%5D%0A%20%20%20%20%20%20%20%20B3%20--%3E%20B4%5Barc-persistence%20%2F%20arc-messaging%20%2F%20arc-cache%20hosts%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22Stable%20%E2%80%94%20codename%20lives%20here%20only%22%0A%20%20%20%20%20%20%20%20C1%5Bservice.yaml%20codename%3A%20sherlock%5D%0A%20%20%20%20%20%20%20%20C2%5BCLI%20display%3A%20Sherlock%20%E2%9C%93%5D%0A%20%20%20%20end%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<h2 id="user-scenarios-testing" tabindex="-1">User Scenarios &amp; Testing <a class="header-anchor" href="#user-scenarios-testing" aria-label="Permalink to &quot;User Scenarios &amp; Testing&quot;">​</a></h2><h3 id="p1-—-must-have" tabindex="-1">P1 — Must Have <a class="header-anchor" href="#p1-—-must-have" aria-label="Permalink to &quot;P1 — Must Have&quot;">​</a></h3><p><strong>US-1</strong>: As a platform developer, I want all internal Python imports to use <code>reasoner</code> as the package name so that the codebase has no coupling to the codename.</p><ul><li><strong>Given</strong>: The reasoner service is running</li><li><strong>When</strong>: I inspect any <code>import</code> or <code>from ... import</code> in <code>services/reasoner/src/</code></li><li><strong>Then</strong>: No statement references <code>sherlock</code> as a module path</li><li><strong>Test</strong>: <code>grep -r &quot;from sherlock&quot; services/reasoner/src/</code> returns zero results</li></ul><p><strong>US-2</strong>: As an agent or SDK consumer, I want NATS subjects to use the functional role name so that my subscription does not break when codenames change.</p><ul><li><strong>Given</strong>: A NATS-connected client subscribing to <code>reasoner.v1.chat</code></li><li><strong>When</strong>: I publish a <code>ChatCompletionRequest</code> to <code>reasoner.v1.chat</code></li><li><strong>Then</strong>: Reasoner processes the request and responds to the reply inbox</li><li><strong>Test</strong>: Integration test publishes to <code>reasoner.v1.chat</code>, asserts response within 5s</li></ul><p><strong>US-3</strong>: As a platform operator, I want Cortex to use functional hostnames in its defaults so that config works without overrides after docker-compose container renames.</p><ul><li><strong>Given</strong>: Default Cortex config (no env overrides)</li><li><strong>When</strong>: Cortex performs health probes for Postgres, NATS, and Redis</li><li><strong>Then</strong>: Probes use <code>arc-persistence</code>, <code>arc-messaging</code>, <code>arc-cache</code> as hostnames</li><li><strong>Test</strong>: <code>arc run --profile think</code> passes all health checks with zero env overrides</li></ul><p><strong>US-4</strong>: As a platform developer, I want the Postgres schema to use <code>reasoner</code> instead of <code>sherlock</code> so that DB introspection matches the service role.</p><ul><li><strong>Given</strong>: Fresh DB migration</li><li><strong>When</strong>: I inspect <code>\\dn</code> in PostgreSQL</li><li><strong>Then</strong>: Schema is named <code>reasoner</code>, not <code>sherlock</code></li><li><strong>Test</strong>: Migration test creates schema, verifies <code>reasoner.vector_stores</code> exists</li></ul><h3 id="p2-—-should-have" tabindex="-1">P2 — Should Have <a class="header-anchor" href="#p2-—-should-have" aria-label="Permalink to &quot;P2 — Should Have&quot;">​</a></h3><p><strong>US-5</strong>: As a consumer of the existing <code>sherlock.*</code> NATS subjects, I want a migration window so that I can update my subscribers without downtime.</p><ul><li><strong>Given</strong>: Old client subscribing to <code>sherlock.v1.chat</code></li><li><strong>When</strong>: Reasoner has both old and new subjects active (migration release)</li><li><strong>Then</strong>: Old subjects still work, response includes deprecation header or log warning</li><li><strong>Test</strong>: Publish to <code>sherlock.v1.chat</code> → receives valid response + deprecation log emitted</li></ul><p><strong>US-6</strong>: As a platform developer, I want OTEL metric and tracer names to use <code>arc-reasoner</code> so that dashboards reflect the service role.</p><ul><li><strong>Given</strong>: Reasoner emitting OTEL metrics</li><li><strong>When</strong>: I query SigNoz for service <code>arc-reasoner</code></li><li><strong>Then</strong>: All metrics and traces appear under <code>arc-reasoner</code></li><li><strong>Test</strong>: Check <code>service_name</code> label in metric output</li></ul><h3 id="p3-—-nice-to-have" tabindex="-1">P3 — Nice to Have <a class="header-anchor" href="#p3-—-nice-to-have" aria-label="Permalink to &quot;P3 — Nice to Have&quot;">​</a></h3><p><strong>US-7</strong>: As a developer reading the codebase, I want <code>pyproject.toml</code> package metadata to reflect <code>arc-reasoner</code> so that package introspection is consistent.</p><ul><li><strong>Given</strong>: Reasoner package installed in dev container</li><li><strong>When</strong>: <code>pip show arc-reasoner</code></li><li><strong>Then</strong>: Package name is <code>arc-reasoner</code>, not <code>arc-sherlock</code></li><li><strong>Test</strong>: <code>pip show</code> output check in CI</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="functional" tabindex="-1">Functional <a class="header-anchor" href="#functional" aria-label="Permalink to &quot;Functional&quot;">​</a></h3><ul><li>[ ] FR-1: Rename Python package directory <code>services/reasoner/src/sherlock/</code> → <code>services/reasoner/src/reasoner/</code></li><li>[ ] FR-2: Update all internal imports from <code>from sherlock.xxx</code> → <code>from reasoner.xxx</code> (all files in the package)</li><li>[ ] FR-3: Update <code>services/reasoner/src/sherlock/config.py</code> NATS subjects: <code>sherlock.*</code> → <code>reasoner.*</code></li><li>[ ] FR-4: Update <code>services/reasoner/src/sherlock/config.py</code> Pulsar topics: <code>sherlock-*</code> → <code>reasoner-*</code></li><li>[ ] FR-5: Update <code>services/reasoner/contracts/asyncapi.yaml</code> channel and operation names to use <code>reasoner.*</code></li><li>[ ] FR-6: Write SQL migration: rename Postgres schema <code>sherlock</code> → <code>reasoner</code> (affecting <code>vector_stores</code> table)</li><li>[ ] FR-7: Update Cortex Go config defaults: <code>arc-oracle</code> → <code>arc-persistence</code>, <code>nats://arc-flash:4222</code> → <code>nats://arc-messaging:4222</code>, <code>arc-sonic</code> → <code>arc-cache</code></li><li>[ ] FR-8: Update Cortex probe names in Go clients to match new hostnames</li><li>[ ] FR-9: Update OTEL service name and meter name from <code>arc-sherlock</code> → <code>arc-reasoner</code></li><li>[ ] FR-10: Update <code>pyproject.toml</code> package name from <code>arc-sherlock</code> → <code>arc-reasoner</code></li><li>[ ] FR-12: Update <code>Dockerfile</code> entrypoints/CMD that reference the <code>sherlock</code> module name</li><li>[ ] FR-13: Rename container <code>arc-sql-db</code> → <code>arc-persistence</code> in all docker-compose files, service.yaml, config files, and make targets that reference it by DNS hostname</li><li>[ ] FR-14: Remove <code>services/vector/</code> (Qdrant/Cerebro) entirely — directory, docker-compose, service.yaml, make targets, and all references from other services — confirmed zero code consumers</li></ul><h3 id="non-functional" tabindex="-1">Non-Functional <a class="header-anchor" href="#non-functional" aria-label="Permalink to &quot;Non-Functional&quot;">​</a></h3><ul><li>[ ] NFR-1: All existing tests pass after rename (ruff, mypy, pytest, golangci-lint)</li><li>[ ] NFR-2: No codename string shall appear in any <code>import</code>, subject definition, schema name, hostname default, or metric label after this change</li><li>[ ] NFR-3: DB migration is idempotent — safe to re-run on already-migrated schema</li><li>[ ] NFR-4: <code>arc run --profile think</code> health checks pass without any env variable overrides</li><li>[ ] NFR-5: No running container, volume, DNS hostname, or profile alias uses <code>arc-sql-db</code>, <code>sql-db</code>, or <code>arc-vector-db</code> after this change</li><li>[ ] NFR-6: Removing <code>services/vector/</code> does not break any profile — confirmed vector was not included in any profile</li></ul><h3 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Entity</th><th>Module</th><th>Description</th></tr></thead><tbody><tr><td><code>reasoner</code> Python package</td><td><code>services/reasoner/src/reasoner/</code></td><td>Renamed package; all internal logic unchanged</td></tr><tr><td>NATS subjects <code>reasoner.*</code></td><td>wire protocol</td><td>New functional subject namespace</td></tr><tr><td><code>reasoner.vector_stores</code> schema</td><td>Postgres</td><td>Renamed from <code>sherlock.vector_stores</code></td></tr><tr><td>Cortex hostname defaults</td><td><code>services/cortex/internal/config/</code></td><td>Updated to functional container DNS names</td></tr><tr><td><code>arc-reasoner</code> OTEL identity</td><td>observability</td><td>Service name used in metrics/traces</td></tr><tr><td><code>arc-persistence</code> container</td><td><code>services/persistence/</code></td><td>Renamed from <code>arc-sql-db</code>; all consumer configs updated</td></tr><tr><td><s><code>services/vector/</code></s></td><td>removed</td><td>Dead Qdrant service deleted; pgvector in Postgres is the vector backend</td></tr></tbody></table><h2 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Expected Behavior</th></tr></thead><tbody><tr><td>DB migration run on schema that is already <code>reasoner</code></td><td>Migration detects existing schema, exits cleanly (idempotent)</td></tr><tr><td>Cortex starts with <code>POSTGRES_HOST=arc-oracle</code> env override</td><td>Old env override still works — env overrides config defaults</td></tr><tr><td>Partially renamed package (some imports old, some new)</td><td>CI ruff/mypy catches unresolved imports; blocks merge</td></tr><tr><td><code>pyproject.toml</code> rename breaks pinned SDK dependency</td><td>SDK must bump package ref; noted as explicit dependency in plan</td></tr><tr><td>Pulsar disabled but topic names in config are old</td><td>Config rename is safe — disabled handler never publishes</td></tr><tr><td><code>services/vector/</code> removal breaks a profile</td><td>Qdrant is confirmed absent from all profiles (<code>think</code>, <code>reason</code>, <code>ultra-instinct</code>) — verified in <code>profiles.yaml</code></td></tr><tr><td><code>arc-sql-db</code> rename breaks a service not in scope</td><td><code>data.mk</code>, <code>flags</code>, <code>otel</code> are all in scope; <code>profiles.yaml</code> uses role alias <code>sql-db</code> which maps to the service — must verify alias is updated too</td></tr></tbody></table><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li>[ ] SC-1: <code>grep -r &quot;from sherlock&quot; services/reasoner/src/</code> returns zero results</li><li>[ ] SC-2: <code>grep -r &quot;sherlock\\.&quot; services/reasoner/src/reasoner/config.py</code> returns zero results (NATS subjects / Pulsar topics)</li><li>[ ] SC-3: <code>\\dn</code> in Postgres shows <code>reasoner</code> schema, not <code>sherlock</code></li><li>[ ] SC-4: <code>arc run --profile think</code> health check passes with zero env overrides on a clean deploy</li><li>[ ] SC-5: Integration test: publish to <code>reasoner.v1.chat</code> → receives valid ChatCompletionResponse</li><li>[ ] SC-6: <code>grep &quot;sql-db&quot; services/profiles.yaml</code> returns zero results</li><li>[ ] SC-7: <code>ruff check services/reasoner/src/</code> passes with zero errors</li><li>[ ] SC-8: <code>mypy services/reasoner/src/</code> passes with zero errors</li><li>[ ] SC-9: <code>golangci-lint run services/cortex/</code> passes with zero errors</li><li>[ ] SC-10: SigNoz shows service name <code>arc-reasoner</code> in trace list (not <code>arc-sherlock</code>)</li><li>[ ] SC-11: <code>grep -r &quot;arc-sql-db&quot; services/</code> returns zero results (excluding git history)</li><li>[ ] SC-12: <code>services/vector/</code> directory does not exist</li><li>[ ] SC-13: <code>arc run --profile think</code> starts successfully with <code>arc-persistence</code> as the Postgres container</li></ul><h2 id="docs-links-update" tabindex="-1">Docs &amp; Links Update <a class="header-anchor" href="#docs-links-update" aria-label="Permalink to &quot;Docs &amp; Links Update&quot;">​</a></h2><ul><li>[ ] Update <code>CLAUDE.md</code> service codename table entry for reasoner: confirm <code>dir: reasoner</code> (already correct), no source path references</li><li>[ ] Update <code>docs/</code> any code samples or config snippets using <code>sherlock.*</code> subjects or <code>from sherlock</code> imports</li><li>[ ] Update <code>.specify/config.yaml</code> if any <code>test_command</code> or <code>lint_command</code> references old package path</li><li>[ ] Update <code>CODENAME-DECOUPLING.md</code> (root) status to &quot;implemented&quot; after merge</li><li>[ ] Verify <code>services/reasoner/contracts/asyncapi.yaml</code> links referenced in docs are still valid after subject rename</li><li>[ ] Update <code>CLAUDE.md</code> service codename table — remove Cerebro/Qdrant row, update persistence row to reflect <code>arc-persistence</code></li><li>[ ] Update <code>NERVOUS-SYSTEM.md</code> (root) — remove stale Cerebro/Qdrant references</li><li>[ ] Update <code>services/data.mk</code> — remove <code>vector-db-*</code> targets, rename <code>sql-db-*</code> targets to <code>persistence-*</code></li></ul><h2 id="constitution-compliance" tabindex="-1">Constitution Compliance <a class="header-anchor" href="#constitution-compliance" aria-label="Permalink to &quot;Constitution Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Applies</th><th>Compliant</th><th>Notes</th></tr></thead><tbody><tr><td>I. Zero-Dep CLI</td><td>[ ]</td><td>—</td><td>Not applicable — no CLI changes</td></tr><tr><td>II. Platform-in-a-Box</td><td>[x]</td><td>[x]</td><td><code>arc run --profile think</code> must still work with zero config after hostname default fixes</td></tr><tr><td>III. Modular Services</td><td>[x]</td><td>[x]</td><td>Each service remains self-contained; rename is internal</td></tr><tr><td>IV. Two-Brain Separation</td><td>[x]</td><td>[x]</td><td>Python package rename stays in Python brain; Go config fixes stay in Go brain</td></tr><tr><td>V. Polyglot Standards</td><td>[x]</td><td>[x]</td><td>ruff + mypy (Python), golangci-lint (Go) must pass post-rename</td></tr><tr><td>VI. Local-First</td><td>[ ]</td><td>—</td><td>Not applicable</td></tr><tr><td>VII. Observability</td><td>[x]</td><td>[x]</td><td>OTEL service name updated to <code>arc-reasoner</code>; no metric gaps introduced</td></tr><tr><td>VIII. Security</td><td>[x]</td><td>[x]</td><td>No secrets involved; non-root containers unchanged</td></tr><tr><td>IX. Declarative</td><td>[ ]</td><td>—</td><td>Not applicable</td></tr><tr><td>X. Stateful Ops</td><td>[ ]</td><td>—</td><td>Not applicable</td></tr><tr><td>XI. Resilience</td><td>[x]</td><td>[x]</td><td>Container rename and profile alias update are atomic across all consumers; no partial state possible</td></tr><tr><td>XII. Interactive</td><td>[ ]</td><td>—</td><td>Not applicable</td></tr></tbody></table>',33))])}const S=a(p,[["render",m]]);export{y as __pageData,S as default};
